#define FOR(i,a,b) for(int i=(a);i<(b);i++)

#define rep(i,N) for(int i=0;i<(N);i++)

#define ALL(s) (s).begin(),(s).end()

const int INF=1e9+7;

const int MOD=1000000007;

typedef long long ll;

typedef pair<int,int> P;

typedef pair<ll,ll> pll;

void solve(){

    int N,C;

    cin>>N>>C;

    C*=N;

    vector<int> L(N);

    rep(i,N) cin>>L[i],L[i]*=N;

    sort(ALL(L));

    double ans=0;

    rep(bit,1<<N){

        int sum=0;

        int cnt=0;

        rep(i,N){

            if(bit>>i&1){

                sum+=L[i];

                cnt++;

            }

        }

        if(sum>C) continue;

        double p=1;

        rep(i,N){

            if(bit>>i&1) continue;

            p*=(double)(C-sum)/(double)(L[i]+sum);

        }

        ans+=p;

    }

    printf("%.15f\n",ans);

}

int main(){

    solve();

    return 0;

}

